Example: average_samples()
uint16_t average_samples(uint16_t values[], int count)
{
    if (count == 0) {
        return 0U;
    }

    uint32_t sum = 0U;
    for (int i = 0; i &lt; count; ++i) {
        sum += values[i];
    }

    return sum / count;
}

Use a 32-bit sum, handle count == 0, loop with i &lt; count, and divide once at the end.

