LCD Library: Source File (lcd_i2c.c)
#include "lcd_i2c.h"

extern I2C_HandleTypeDef hi2c1; // Change to your I2C handle
#define SLAVE_ADDRESS_LCD 0x4E // Change to your address (0x27 &lt;&lt; 1)

void lcd_send_cmd(char cmd) {
  char data_u, data_l;
  uint8_t data_t[4];
  data_u = (cmd & 0xf0);
  data_l = ((cmd &lt;&lt; 4) & 0xf0);
  data_t[0] = data_u | 0x0C;  // en=1, rs=0
  data_t[1] = data_u | 0x08;  // en=0, rs=0
  data_t[2] = data_l | 0x0C;  // en=1, rs=0
  data_t[3] = data_l | 0x08;  // en=0, rs=0
  HAL_I2C_Master_Transmit(&hi2c1, SLAVE_ADDRESS_LCD, (uint8_t *) data_t, 4, 100);
}

void lcd_send_data(char data) {
  char data_u, data_l;
  uint8_t data_t[4];
  data_u = (data & 0xf0);
  data_l = ((data &lt;&lt; 4) & 0xf0);
  data_t[0] = data_u | 0x0D;  // en=1, rs=1
  data_t[1] = data_u | 0x09;  // en=0, rs=1
  data_t[2] = data_l | 0x0D;  // en=1, rs=1
  data_t[3] = data_l | 0x09;  // en=0, rs=1
  HAL_I2C_Master_Transmit(&hi2c1, SLAVE_ADDRESS_LCD, (uint8_t *) data_t, 4, 100);
}

void lcd_init(void) {
  lcd_send_cmd(0x33); // 1. Reset / Initialization
  lcd_send_cmd(0x32); // 2. Switch to 4-bit mode
  lcd_send_cmd(0x28); // 3. Function Set: 4-bit, 2 lines, 5x8 dots
  lcd_send_cmd(0x0C); // 4. Display Control: Display ON, Cursor OFF
  lcd_send_cmd(0x06); // 5. Entry Mode: Auto-increment cursor (left-to-right)
  lcd_send_cmd(0x01); // 6. Clear Display
  HAL_Delay(2);       // 7. Wait for Clear command to finish (requires &gt;1.52ms)
}

void lcd_send_string(char *str) {
  while (*str) lcd_send_data(*str++);
}

void lcd_clear(void) {
  lcd_send_cmd(0x01);
  HAL_Delay(2);
}

void lcd_set_cursor(int row, int col) {
    uint8_t pos = (row == 0) ? 0x80 + col : 0xC0 + col;
    lcd_send_cmd(pos);
}

